mapper.select:
SELECT id, dict_type, dict_label, dict_value, dict_sort, status, remark, create_time FROM sys_dict_data WHERE del_flag = '0' AND dict_type = #{query.dictType}
AND dict_label LIKE CONCAT('%', #{query.dictLabel}, '%')
AND dict_value LIKE CONCAT('%', #{query.dictValue}, '%')
AND status = #{query.status}
ORDER BY dict_sort
